// Acting Components
instance HeatbedActuator : DTDFVocab:ActingComponent [
    base:desc "Electric heating element heatbed controlled by Raspberry Pi GPIO via MOSFETs and optocouplers."
]

instance FanActuator : DTDFVocab:ActingComponent [
    base:desc "12‑24 V fan driven by Raspberry Pi GPIO through MOSFETs and optocouplers, controlled by on/off commands from the controller."
]

// Sensing Components
instance InsideTemperatureSensorOne : DTDFVocab:SensingComponent [
    base:desc "DS18S20 one‑wire digital thermometer (±0.5 °C accuracy) positioned inside the incubator."
    DTDFVocab:producedData InsideTemperatureReadingMessage
]

instance InsideTemperatureSensorTwo : DTDFVocab:SensingComponent [
    base:desc "DS18S20 one‑wire digital thermometer (±0.5 °C accuracy) positioned inside the incubator."
    DTDFVocab:producedData InsideTemperatureReadingMessage
]

instance AmbientTemperatureSensor : DTDFVocab:SensingComponent [
    base:desc "DS18S20 thermometer (±0.5 °C accuracy) positioned outside the incubator to capture ambient temperature."
    DTDFVocab:producedData AmbientTemperatureReadingMessage
]

// Data Transmitted
instance InsideTemperatureReadingMessage : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom InsideTemperatureSensorOne, InsideTemperatureSensorTwo
]

instance AmbientTemperatureReadingMessage : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom AmbientTemperatureSensor
]

instance ActuatorStateMessage : DTDFVocab:DataTransmitted [
    base:desc "State of heatbed/fan actuators transmitted by controller."
]

// Data Instances
instance InsideTemperatureData : DTDFVocab:Data [
    base:desc "Time‑series of inside temperature samples extracted from InsideTemperatureReadingMessage."
    DTDFVocab:fromData InsideTemperatureReadingMessage
    DTDFVocab:inputTo CentralControllerEnabler, CalibrationEnabler
]

instance AmbientTemperatureData : DTDFVocab:Data [
    base:desc "Time‑series of ambient temperature samples extracted from AmbientTemperatureReadingMessage."
    DTDFVocab:fromData AmbientTemperatureReadingMessage
    DTDFVocab:inputTo CentralControllerEnabler, CalibrationEnabler
]

instance ActuatorStateData : DTDFVocab:Data [
    base:desc "Time‑series of actuator status (heatbed, fan) samples extracted from ActuatorStateMessage."
    DTDFVocab:fromData ActuatorStateMessage
    DTDFVocab:inputTo CentralControllerEnabler, CalibrationEnabler
]

// Models
instance ModelAThermalModel : DTDFVocab:Model [
    base:desc "dT/dt = (VI Δt – G_box (T_air – T_room)) / C_air – four‑parameter analytical thermal model."
    DTDFVocab:inputTo CalibrationEnabler
]

instance ModelBThermalModel : DTDFVocab:Model [
    base:desc "dT/dt equations incorporating G_heater, C_heater, C_air, G_box – six‑parameter analytical temperature prediction model."
    DTDFVocab:inputTo CalibrationEnabler
]

// Enablers
instance CentralControllerEnabler : DTDFVocab:Enabler [
    base:desc "Raspberry Pi 4 Model B controller running low‑level driver and RabbitMQ broker, enabling real‑time monitoring and bang‑bang control."
    DTDFVocab:enables TemperatureMonitoringService, BangBangControlService
    DTDFVocab:enables TemperatureSimulationServiceA, TemperatureSimulationServiceB
]

instance CalibrationEnabler : DTDFVocab:Enabler [
    base:desc "Python runtime on Raspberry Pi performing offline calibration, nonlinear least‑squares (SciPy), and parameter estimation for thermal models."
    DTDFVocab:enables CalibrationService, ParameterEstimationService
]

// Services
instance TemperatureMonitoringService : DTDFVocab:Service [
    base:desc "Real‑time monitoring of temperature using InsideTemperatureData and AmbientTemperatureData."
    DTDFVocab:provides TemperatureMonitoringInsight
]

instance BangBangControlService : DTDFVocab:Service [
    base:desc "Bang‑bang control logic for heatbed and fan actuators based on temperature thresholds."
    DTDFVocab:provides BangBangControlAction
]

instance TemperatureSimulationServiceA : DTDFVocab:Service [
    base:desc "Simulation of temperature dynamics using ModelAThermalModel."
    DTDFVocab:provides ModelATemperaturePredictionInsight
]

instance TemperatureSimulationServiceB : DTDFVocab:Service [
    base:desc "Simulation of temperature dynamics using ModelBThermalModel."
    DTDFVocab:provides ModelBTemperaturePredictionInsight
]

instance CalibrationService : DTDFVocab:Service [
    base:desc "Offline calibration of thermal model parameters using historical data."
    DTDFVocab:provides ParameterEstimationInsight
]

instance ParameterEstimationService : DTDFVocab:Service [
    base:desc "Parameter estimation of C_air, G_box, G_heater from temperature time‑series."
    DTDFVocab:provides AdjustHeatingParameterAction, AdjustCoolingParameterAction
]

