instance TemperatureMonitoringInsight : DTDFVocab:Insight [
    base:desc "Insight on recent temperature trend for visualization."
]

instance ModelATemperaturePredictionInsight : DTDFVocab:Insight [
    base:desc "Predicted temperature trajectory from ModelAThermalModel."
]

instance ModelBTemperaturePredictionInsight : DTDFVocab:Insight [
    base:desc "Predicted temperature trajectory from ModelBThermalModel."
]

instance ParameterEstimationInsight : DTDFVocab:Insight [
    base:desc "Estimated values of C_air, G_box, G_heater, enabling adjustment of control parameters."
]

instance OscillationDetectionInsight : DTDFVocab:Insight [
    base:desc "Detection of temperature oscillations indicating instability."
]

