]

instance AdjustHeatingParameterAction : DTDFVocab:Action [
    base:desc "Automatic adjustment of heating duration H based on ParameterEstimationInsight."
    DTDFVocab:IsAutomatic true
]

instance AdjustCoolingParameterAction : DTDFVocab:Action [
    base:desc "Automatic adjustment of cooling parameter C based on OscillationDetectionInsight."
    DTDFVocab:IsAutomatic true
]

// Environment
instance IncubatorDigitalTwinEnvironment : DTDFVocab:Environment [
    base:desc "Digital twin environment containing all virtual and physical components of the incubator."
    base:contains HeatbedActuator, FanActuator,
                 InsideTemperatureSensorOne, InsideTemperatureSensorTwo, AmbientTemperatureSensor,
                 CentralControllerEnabler, CalibrationEnabler,
                 TemperatureMonitoringService, BangBangControlService,
                 TemperatureSimulationServiceA, TemperatureSimulationServiceB,
                 CalibrationService, ParameterEstimationService
